struct SeedDef {
  const char* function_id;
  const char* function_uuid;
  const char* family;
  const char* short_name;
  FunctionImplementationState implementation_state;
  FunctionPackageState package_state;
};

struct NameSeedDef {
  const char* name_lookup_seed_id;
  const char* function_uuid;
  const char* canonical_function_id;
  const char* name_namespace;
  const char* language;
  const char* name_class;
  const char* name;
  const char* target_kind;
  const char* parser_profile;
  const char* notes;
};

